package test;

import org.eclipse.jdt.ui.PreferenceConstants;
import org.eclipse.jface.preference.IPreferenceStore;

class Test {
    void setup(IPreferenceStore store) {
        // This should not be changed if it's not 200
        store.setDefault(PreferenceConstants.CODEASSIST_AUTOACTIVATION_DELAY, 100);
        // This should not be changed if it's a different preference key
        store.setDefault("some.other.preference", 200);
        // This should not be changed if it's already 0
        store.setDefault(PreferenceConstants.CODEASSIST_AUTOACTIVATION_DELAY, 0);
    }
}
